import re

def fill_prompt_template(template: str, variables: dict[str, str]) -> str:
    placeholders = re.findall(r'\{([a-zA-Z_][a-zA-Z0-9_]*)\}', template)
    missing = set(placeholders) - set(variables.keys())
    if missing:
        raise ValueError(f"Missing required variables: {', '.join(missing)}")
    return template.format(**variables)

# Example:
template = """You are a {role} helping with {task}.
Audience: {audience}
Tone: {tone}

Please provide:
1. Overview of {topic}
2. Three key takeaways
3. Next steps"""

result = fill_prompt_template(template, {
    "role": "senior data engineer",
    "task": "technical documentation",
    "audience": "junior developers",
    "tone": "professional but approachable",
    "topic": "Apache Kafka"
})
