from openai import OpenAI
import json

client = OpenAI()

def generate_prompt_variants(base_prompt, task, n=3):
    response = client.chat.completions.create(
        model="gpt-4", temperature=0.8,
        messages=[{"role": "user",
            "content": f"Generate {n} variations of this prompt for: {task}\n\nOriginal: {base_prompt}\n\nReturn as JSON array of strings."}])
    return json.loads(response.choices[0].message.content)

def evaluate_prompt(prompt, test_cases):
    correct = 0
    for case in test_cases:
        response = client.chat.completions.create(
            model="gpt-4", temperature=0,
            messages=[{"role": "user", "content": f"{prompt}\n\nInput: {case['input']}\nOutput:"}])
        if response.choices[0].message.content.strip().lower() == case['expected'].lower():
            correct += 1
    return correct / len(test_cases)

def optimize_prompt(base_prompt, task, test_cases, iterations=3):
    best_prompt = base_prompt
    best_score = evaluate_prompt(base_prompt, test_cases)
    for i in range(iterations):
        variants = generate_prompt_variants(best_prompt, task)
        for j, variant in enumerate(variants):
            score = evaluate_prompt(variant, test_cases)
            if score > best_score:
                best_prompt, best_score = variant, score
    return best_prompt, best_score
