import json
from datetime import datetime
from pathlib import Path

class PromptVersionManager:
    def __init__(self, storage_path="prompts"):
        self.storage = Path(storage_path)
        self.storage.mkdir(exist_ok=True)

    def save_version(self, name, content, author, change_note, model="gpt-4"):
        f = self.storage / f"{name}.json"
        data = json.loads(f.read_text()) if f.exists() else {"versions": []}
        v_num = len(data["versions"]) + 1
        version = {
            "version": f"v{v_num}.0.0", "content": content,
            "author": author, "change_note": change_note,
            "model": model, "timestamp": datetime.now().isoformat(),
            "metrics": {}
        }
        data["versions"].append(version)
        data["current"] = version["version"]
        f.write_text(json.dumps(data, indent=2))
        return version["version"]

    def get_version(self, name, version=None):
        data = json.loads((self.storage / f"{name}.json").read_text())
        v = version or data["current"]
        return next((x for x in data["versions"] if x["version"] == v), None)

    def rollback(self, name, target_version):
        f = self.storage / f"{name}.json"
        data = json.loads(f.read_text())
        data["current"] = target_version
        f.write_text(json.dumps(data, indent=2))

    def update_metrics(self, name, version, metrics):
        f = self.storage / f"{name}.json"
        data = json.loads(f.read_text())
        for v in data["versions"]:
            if v["version"] == version:
                v["metrics"].update(metrics)
        f.write_text(json.dumps(data, indent=2))
